def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.2:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        additive = 0.0
        for j in range(1, 10):
            if j % 4 == 0:
                decay *= 0.9
            if ratio < (0.05 * j):
                score += (j ** 1.5) * (1 - ratio)**2 * decay
                if cap % (j+1) == 0:
                    score += np.log1p(j)
                else:
                    score -= np.sqrt(j)
            else:
                score += j * np.exp(-ratio * j) * decay / (j+1)
                if (cap + j) % 3 == 0:
                    score += np.sin(ratio * j)
                else:
                    score -= np.cos(ratio * j)
            if j % 2 == 1:
                additive += np.tanh(score / (j + 1))
            else:
                additive -= np.arctan(score / (j + 1))
        for k in range(1, 5):
            residual = cap - item * k
            if residual > 0:
                if residual % k == 0:
                    score += np.log1p(residual) / (k + 0.5)
                else:
                    score -= (residual ** 0.25) / (k + 1.5)
            else:
                score -= abs(residual) * 0.1 * k
        final_value = (score + additive) / (cap + 1)
        if final_value > 0:
            priorities[i] = -final_value * np.exp(-ratio)
        else:
            priorities[i] = -final_value * (np.log1p(cap) + np.sqrt(item))
    return priorities
